var maxTrailingZeros = function(grid) {
    const f2 = (x) => { let c = 0; while (x % 2 === 0) { c++; x = Math.floor(x / 2); } return c; };
    const f5 = (x) => { let c = 0; while (x % 5 === 0) { c++; x = Math.floor(x / 5); } return c; };
    const m = grid.length, n = grid[0].length;
    const t = Array.from({ length: m }, (_, i) => grid[i].map(f2));
    const fv = Array.from({ length: m }, (_, i) => grid[i].map(f5));
    const rt = Array.from({ length: m }, () => new Array(n + 1).fill(0));
    const rf = Array.from({ length: m }, () => new Array(n + 1).fill(0));
    const ct = Array.from({ length: n }, () => new Array(m + 1).fill(0));
    const cf = Array.from({ length: n }, () => new Array(m + 1).fill(0));
    for (let i = 0; i < m; i++) for (let j = 0; j < n; j++) { rt[i][j + 1] = rt[i][j] + t[i][j]; rf[i][j + 1] = rf[i][j] + fv[i][j]; }
    for (let j = 0; j < n; j++) for (let i = 0; i < m; i++) { ct[j][i + 1] = ct[j][i] + t[i][j]; cf[j][i + 1] = cf[j][i] + fv[i][j]; }
    let best = 0;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const left2 = rt[i][j + 1], left5 = rf[i][j + 1];
            const right2 = rt[i][n] - rt[i][j], right5 = rf[i][n] - rf[i][j];
            const up2 = ct[j][i + 1], up5 = cf[j][i + 1];
            const down2 = ct[j][m] - ct[j][i], down5 = cf[j][m] - cf[j][i];
            const cell2 = t[i][j], cell5 = fv[i][j];
            const harms = [[left2, left5], [right2, right5]];
            const varms = [[up2, up5], [down2, down5]];
            for (const [h2, h5] of harms) for (const [v2, v5] of varms) {
                const tot2 = h2 + v2 - cell2;
                const tot5 = h5 + v5 - cell5;
                best = Math.max(best, Math.min(tot2, tot5));
            }
        }
    }
    return best;
};
